// Merge Stripe data with historical data
const stripeCharges = $input.first().json.data || [];
const subscriptions = $input.all()[1]?.json.data || [];
const refunds = $input.all()[2]?.json.data || [];
const historicalData = $input.all()[3]?.json.values || [];

// Process charges
const chargeData = stripeCharges.map(charge => ({
  date: new Date(charge.created * 1000).toISOString().split('T')[0],
  amount: charge.amount / 100,
  currency: charge.currency,
  customer_id: charge.customer,
  type: 'charge',
  status: charge.status
}));

// Process subscriptions
const subscriptionData = subscriptions.map(sub => ({
  date: new Date(sub.created * 1000).toISOString().split('T')[0],
  amount: sub.items.data[0]?.price?.unit_amount / 100 || 0,
  currency: sub.currency,
  customer_id: sub.customer,
  type: 'subscription',
  status: sub.status,
  interval: sub.items.data[0]?.price?.recurring?.interval
}));

// Process refunds
const refundData = refunds.map(refund => ({
  date: new Date(refund.created * 1000).toISOString().split('T')[0],
  amount: -(refund.amount / 100),
  currency: refund.currency,
  customer_id: refund.charge?.customer,
  type: 'refund',
  status: refund.status
}));

// Combine all data
const allSalesData = [...chargeData, ...subscriptionData, ...refundData];

// Group by date and calculate daily totals
const dailyTotals = {};
allSalesData.forEach(item => {
  if (!dailyTotals[item.date]) {
    dailyTotals[item.date] = {
      date: item.date,
      total_revenue: 0,
      charges: 0,
      subscriptions: 0,
      refunds: 0,
      net_revenue: 0
    };
  }

  dailyTotals[item.date].total_revenue += item.amount;
  dailyTotals[item.date][item.type + 's'] += item.amount;
  if (item.type !== 'refund') {
    dailyTotals[item.date].net_revenue += item.amount;
  } else {
    dailyTotals[item.date].net_revenue += item.amount; // Already negative
  }
});

// Convert to array and sort by date
const processedData = Object.values(dailyTotals)
  .sort((a, b) => new Date(a.date) - new Date(b.date));

return [{ json: { processed_sales_data: processedData, raw_data: allSalesData } }];

// Calculate trends and metrics
const salesData = $json.processed_sales_data;
const currentWeekStart = new Date();
currentWeekStart.setDate(currentWeekStart.getDate() - 7);

// Calculate weekly aggregates
const currentWeekData = salesData.filter(d => 
  new Date(d.date) >= currentWeekStart
);

const currentWeekRevenue = currentWeekData.reduce((sum, d) => sum + d.net_revenue, 0);
const currentWeekTransactions = currentWeekData.length;

// Calculate previous week for comparison
const previousWeekStart = new Date(currentWeekStart);
previousWeekStart.setDate(previousWeekStart.getDate() - 7);
const previousWeekEnd = new Date(currentWeekStart);

const previousWeekData = salesData.filter(d => {
  const date = new Date(d.date);
  return date >= previousWeekStart && date < previousWeekEnd;
});

const previousWeekRevenue = previousWeekData.reduce((sum, d) => sum + d.net_revenue, 0);

// Calculate growth rate
const weekOverWeekGrowth = previousWeekRevenue > 0 ? 
  ((currentWeekRevenue - previousWeekRevenue) / previousWeekRevenue) * 100 : 0;

// Calculate moving averages (7-day)
const last30Days = salesData.slice(-30);
const movingAverage7Day = last30Days.slice(-7)
  .reduce((sum, d) => sum + d.net_revenue, 0) / 7;

// Calculate MRR (Monthly Recurring Revenue) estimate
const monthlyData = salesData.slice(-30);
const estimatedMRR = monthlyData
  .filter(d => d.date >= new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0])
  .reduce((sum, d) => sum + d.subscriptions, 0);

// Detect anomalies (revenue 50% higher or lower than moving average)
const anomalies = [];
for (let i = 6; i < salesData.length; i++) {
  const current = salesData[i].net_revenue;
  const avgPrevious7 = salesData.slice(i-7, i)
    .reduce((sum, d) => sum + d.net_revenue, 0) / 7;

  if (Math.abs(current - avgPrevious7) / avgPrevious7 > 0.5) {
    anomalies.push({
      date: salesData[i].date,
      value: current,
      expected: avgPrevious7,
      deviation: ((current - avgPrevious7) / avgPrevious7) * 100
    });
  }
}

const trendAnalysis = {
  current_week: {
    revenue: Math.round(currentWeekRevenue * 100) / 100,
    transactions: currentWeekTransactions
  },
  previous_week: {
    revenue: Math.round(previousWeekRevenue * 100) / 100
  },
  growth_metrics: {
    week_over_week_growth: Math.round(weekOverWeekGrowth * 100) / 100,
    moving_average_7day: Math.round(movingAverage7Day * 100) / 100,
    estimated_mrr: Math.round(estimatedMRR * 100) / 100
  },
  anomalies: anomalies,
  has_significant_change: Math.abs(weekOverWeekGrowth) > 20
};

return [{ json: trendAnalysis }];

